import io

def fix_indentation(code_block: str) -> str:
    lines = io.StringIO(code_block).readlines()
    fixed_lines = []
    current_indent_level = 0
    indent_unit = 4

    block_closing_keywords_for_indent_adjustment = {"elif", "else", "except", "finally"}

    for line in lines:
        stripped_line = line.strip()

        if not stripped_line:
            fixed_lines.append("")
            continue

        effective_indent_for_this_line = current_indent_level

        first_word = stripped_line.split(' ', 1)[0].split('(', 1)[0].split(':', 1)[0]
        if first_word in block_closing_keywords_for_indent_adjustment and current_indent_level > 0:
            effective_indent_for_this_line -= 1

        fixed_lines.append((' ' * (effective_indent_for_this_line * indent_unit)) + stripped_line)

        if stripped_line.endswith(':'):
            current_indent_level = effective_indent_for_this_line + 1

    return "\n".join(fixed_lines)
